import { Company } from '../models/company-list';
import { WorkHistoryModel } from "../models/work-history";
import { Project } from "../models/project-list";
import { BASE_URL } from '../../helpers/constants';


export const getWorkHistorys = () : Promise<WorkHistoryModel[]> => {
    return fetch(BASE_URL + '/fake-db/word-history.json').then(res => res.json());
}


export const getProjectList = (): Promise<Project[]> => {
    return fetch(BASE_URL + '/fake-db/projects.json').then(res => res.json());;
}


export const getCompanyList = (): Promise<Company[]> => {
    return fetch(BASE_URL + '/fake-db/companies.json').then(res => res.json());;
}